parameters.jsCode:
// Extract and clean CSV output from agent
let rawOutput = ($json.output || '').trim();

// Strip markdown code fences if the LLM added them
if (rawOutput.includes('```')) {
  const match = rawOutput.match(/```(?:csv)?\r?\n([\s\S]*?)```/);
  if (match) rawOutput = match[1].trim();
}

// Ensure header is present
const expectedHeader = 'TC_ID,Title,Preconditions,Test_Steps,Expected_Result,Test_Data,Priority,Test_Type';
if (!rawOutput.startsWith('TC_ID')) {
  rawOutput = expectedHeader + '\n' + rawOutput;
}

const testCasesCSV = rawOutput;
const testPlan = $('Process Test Plan').item.json.testPlan;
const prdText = $('Set PRD Context').item.json.prdText;
const projectName = $('Set PRD Context').item.json.projectName;
const focusArea = $('Set PRD Context').item.json.focusArea;

// Count rows for logging
const rowCount = testCasesCSV.split('\n').filter(r => r.trim() && !r.startsWith('TC_ID')).length;
console.log(`Test cases generated: ${rowCount}`);

return [{
  json: {
    testCasesCSV,
    testPlan,
    prdText,
    projectName,
    focusArea,
    tcCount: rowCount
  }
}];

