parameters.jsCode:
// Extract playwright markdown output and assemble final payload
const playwrightMD = ($json.output || '').trim();
const testCasesCSV = $('Format CSV Output').item.json.testCasesCSV;
const testPlan = $('Process Test Plan').item.json.testPlan;
const projectName = $('Set PRD Context').item.json.projectName;
const tcCount = $('Format CSV Output').item.json.tcCount;

console.log(`Playwright MD length: ${playwrightMD.length} chars`);

return [{
  json: {
    testPlan,
    testCasesCSV,
    playwrightMD,
    projectName,
    tcCount
  }
}];

// n8n Cloud does not allow 'fs' or 'path' modules.
// All STLC artifacts are returned as JSON so you can copy them
// or pipe them into a Google Drive / Gmail / S3 node downstream.

const timestamp = new Date().toISOString().slice(0, 19).replace('T', '_');

console.log('=== STLC ARTIFACTS READY =========================');
console.log('Project     :', $json.projectName);
console.log('Test Cases  :', $json.tcCount);
console.log('Timestamp   :', timestamp);
console.log('=================================================');

return [{
  json: {
    success: true,
    project: $json.projectName,
    testCaseCount: $json.tcCount,
    timestamp: timestamp,
    artifacts: {
      'test_plan.md':              $json.testPlan,
      'test_cases.csv':            $json.testCasesCSV,
      'playwright_test_cases.md':  $json.playwrightMD
    },
    summary: `STLC artifacts for "${$json.projectName}" generated successfully. ${$json.tcCount} test cases.`,
    note: "n8n Cloud: fs is not available. Copy artifact content from this output, or add Google Drive / Gmail nodes downstream to save the files."
  }
}];

// Split the 3 artifacts into separate items and convert each to binary
// so the Google Drive node can upload them individually.
const artifacts = $json.artifacts;
const project   = $json.project;
const timestamp = $json.timestamp;

const files = [
  { fileName: 'test_plan.md',            content: artifacts['test_plan.md'],            mimeType: 'text/markdown' },
  { fileName: 'test_cases.csv',           content: artifacts['test_cases.csv'],           mimeType: 'text/csv'      },
  { fileName: 'playwright_test_cases.md', content: artifacts['playwright_test_cases.md'], mimeType: 'text/markdown' }
];

const results = [];
for (const file of files) {
  const binaryData = await this.helpers.prepareBinaryData(
    Buffer.from(file.content, 'utf8'),
    file.fileName,
    file.mimeType
  );
  results.push({
    json:   { fileName: file.fileName, project, timestamp },
    binary: { fileData: binaryData }
  });
}

return results;
